
/* ---------------------------------------------------------
   SATHVA SIRI — Malenadu farm goods, light/dark storefront
   Product photography above is cropped directly from the
   shop's own posters. Colors, type, and the ganna (wood
   press) motif carry the brand's existing visual language.
--------------------------------------------------------- */

import React, { useState, useMemo, useEffect } from "react";
import {
  ShoppingBag,
  Sun,
  Moon,
  Plus,
  Minus,
  X,
  MapPin,
  Phone,
  Mail,
  Instagram,
  Check,
  Trash2,
  Leaf,
} from "lucide-react";
const PRODUCT_IMAGES = {
  chilli: "data:image/jpeg;base64,",
  honey: "data:image/jpeg;base64,",
  coconut: "data:image/jpeg;base64,",
  groundnut: "data:image/jpeg;base64,",
  ghee: "data:image/jpeg;base64,",
  honeyHero: "data:image/jpeg;base64,",
};

const ORDER_EMAIL = "djoshmithadevarakonda@gmail.com";
const CONTACT_EMAIL = "sathvasiri@gmail.com";

const PRODUCTS = [
  {
    id: "chilli",
    name: "Jeerige Menasu",
    sub: "ಜೀರಿಗೆ ಮೆಣಸು",
    tag: "Hand-picked",
    unit: "1 kg",
    price: 320,
    desc: "Sun-dried bird's-eye chillies, hand-picked from Malenadu farms. Deep colour, gentle heat.",
  },
  {
    id: "honey",
    name: "Tuduve Forest Honey",
    sub: "ತುಡುವೆ ಜೇನುತುಪ್ಪ",
    tag: "Wild-harvested",
    unit: "500 ml",
    price: 450,
    desc: "Rare Tuduve-flower honey, wild-harvested from the forests of Malenadu. Unprocessed, unblended.",
  },
  {
    id: "coconut",
    name: "Wood-Pressed Coconut Oil",
    sub: "ಕೊಬ್ಬರಿ ಎಣ್ಣೆ",
    tag: "Ganna-pressed",
    unit: "1 L",
    price: 340,
    desc: "Cold, wood-pressed coconut oil, drawn in small batches the traditional ganna way.",
  },
  {
    id: "groundnut",
    name: "Wood-Pressed Groundnut Oil",
    sub: "ಶೇಂಗಾ ಎಣ್ಣೆ",
    tag: "Ganna-pressed",
    unit: "1 L",
    price: 300,
    desc: "Stone-pressed groundnut oil with a rich, nutty aroma. No refining, no additives.",
  },
  {
    id: "ghee",
    name: "Malenadu Gidda Cow Ghee",
    sub: "ಮಲೆನಾಡು ಗಿಡ್ಡ ತುಪ್ಪ",
    tag: "Bilona method",
    unit: "500 ml",
    price: 950,
    desc: "Handmade, Bilona-method ghee churned from Malenadu Gidda desi cow milk.",
  },
];

function BrandMark({ className }) {
  // a simple leaf on a dark roundel — ties back to the "from the Malenadu
  // hills" leaf badge used elsewhere on the page, and reads cleanly at
  // small header sizes since it's the same icon set already used in the UI
  return (
    <div className={`${className} rounded-xl flex items-center justify-center shrink-0`} style={{ background: "#2A1D12" }}>
      <Leaf size={18} style={{ color: "#E0B84B" }} />
    </div>
  );
}

export default function SathvaSiri() {
  const [dark, setDark] = useState(false);
  const [cart, setCart] = useState({}); // id -> qty
  const [cartOpen, setCartOpen] = useState(false);
  const [checkoutOpen, setCheckoutOpen] = useState(false);
  const [checkoutItems, setCheckoutItems] = useState(null); // null = whole cart
  const [form, setForm] = useState({ name: "", phone: "", email: "", address: "" });
  const [placed, setPlaced] = useState(false);
  const [mailtoLink, setMailtoLink] = useState("");
  const [orderText, setOrderText] = useState("");
  const [copied, setCopied] = useState(false);
  const [sending, setSending] = useState(false);
  const [sendError, setSendError] = useState("");
  const [viewProduct, setViewProduct] = useState(null);
  const [slide, setSlide] = useState(0);

  const HERO_SLIDES = [
    { key: "honeyHero", caption: "Tuduve forest honey, wild-harvested." },
    { key: "chilli", caption: "Jeerige menasu, sun-dried by hand." },
    { key: "coconut", caption: "Wood-pressed coconut oil, the ganna way." },
    { key: "groundnut", caption: "Stone-pressed groundnut oil, small batches." },
    { key: "ghee", caption: "Malenadu Gidda cow ghee, Bilona method." },
  ];

  useEffect(() => {
    const timer = setInterval(() => {
      setSlide((s) => (s + 1) % HERO_SLIDES.length);
    }, 3200);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    document.title = "Sathva Siri — Malenadu Farm Goods";
    const svg = `<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 64 64'>
      <rect width='64' height='64' rx='16' fill='#2A1D12'/>
      <path d='M20 44 C20 26, 32 18, 46 18 C46 34, 36 44, 20 44 Z' fill='#E0B84B'/>
      <path d='M22 42 C30 34, 38 26, 45 19' stroke='#2A1D12' stroke-width='2' fill='none' stroke-linecap='round'/>
    </svg>`;
    const href = `data:image/svg+xml,${encodeURIComponent(svg)}`;
    let link = document.querySelector("link[rel~='icon']");
    if (!link) {
      link = document.createElement("link");
      link.rel = "icon";
      document.head.appendChild(link);
    }
    link.href = href;
    link.type = "image/svg+xml";
  }, []);

  function scrollToSection(id) {
    const el = document.getElementById(id);
    if (el) el.scrollIntoView({ behavior: "smooth", block: "start" });
  }

  const t = {
    bg: dark ? "#17130E" : "#FBF6EA",
    surface: dark ? "#221C15" : "#FFFFFF",
    surfaceAlt: dark ? "#2A231A" : "#F3EBD8",
    text: dark ? "#F2EBDC" : "#2A1D12",
    textMuted: dark ? "#B7AA92" : "#6E5C46",
    border: dark ? "#3A3126" : "#E4D6B8",
    gold: dark ? "#E0B84B" : "#A9750F",
    green: dark ? "#7FB07F" : "#3F5B3F",
  };

  const cartCount = useMemo(() => Object.values(cart).reduce((a, b) => a + b, 0), [cart]);
  const cartLines = useMemo(
    () =>
      Object.entries(cart)
        .filter(([, qty]) => qty > 0)
        .map(([id, qty]) => ({ ...PRODUCTS.find((p) => p.id === id), qty })),
    [cart]
  );
  const cartTotal = cartLines.reduce((sum, l) => sum + l.qty * l.price, 0);

  function addToCart(id, qty = 1) {
    setCart((c) => ({ ...c, [id]: (c[id] || 0) + qty }));
  }
  function setQty(id, qty) {
    setCart((c) => ({ ...c, [id]: Math.max(0, qty) }));
  }
  function removeItem(id) {
    setCart((c) => {
      const n = { ...c };
      delete n[id];
      return n;
    });
  }

  function buyNow(product) {
    setCheckoutItems([{ ...product, qty: 1 }]);
    setPlaced(false);
    setSendError("");
    setCheckoutOpen(true);
  }
  function checkoutCart() {
    if (cartLines.length === 0) return;
    setCheckoutItems(null); // use live cart
    setPlaced(false);
    setSendError("");
    setCheckoutOpen(true);
  }

  const itemsForCheckout = checkoutItems ?? cartLines;
  const checkoutTotal = itemsForCheckout.reduce((s, l) => s + l.qty * l.price, 0);

  async function submitOrder(e) {
    e.preventDefault();
    if (!form.name.trim() || form.phone.length !== 10 || !form.email.trim() || !form.address.trim()) return;

    setSending(true);
    setSendError("");

    try {
  const res = await fetch('/api/send-order',{
    method: "POST",
    headers: {
      "Content-Type": "application/json",
    },
    body: JSON.stringify({
      name: form.name,
      phone: form.phone,
      email: form.email,
      address: form.address,
      items: itemsForCheckout,
      total: checkoutTotal,
    }),
  });

      if (!res.ok) throw new Error("Request failed");

      setPlaced(true);
      if (checkoutItems === null) setCart({});
    } catch (err) {
      console.error("Order send failed:", err);
      // Fall back to a mailto link + copyable text so the order is never lost
      const lines = itemsForCheckout
        .map((l) => `- ${l.name} (${l.unit}) x ${l.qty} = Rs. ${l.qty * l.price}`)
        .join("\n");

      const body =
        `New order from Sathva Siri website\n\n` +
        `Customer name: ${form.name}\n` +
        `Phone: ${form.phone}\n` +
        `Email: ${form.email}\n` +
        `Delivery address: ${form.address}\n\n` +
        `Order items:\n${lines}\n\n` +
        `Total: Rs. ${checkoutTotal}\n`;

      const subject = "New Order - Sathva Siri";
      const mailto = `mailto:${ORDER_EMAIL}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;

      setMailtoLink(mailto);
      setOrderText(`To: ${ORDER_EMAIL}\nSubject: ${subject}\n\n${body}`);
      setCopied(false);
      setSendError("We couldn't reach our order system automatically. Please use one of the options below to send us your order.");
      setPlaced(true);
    } finally {
      setSending(false);
    }
  }

  async function copyOrderDetails() {
    try {
      if (navigator.clipboard && navigator.clipboard.writeText) {
        await navigator.clipboard.writeText(orderText);
      } else {
        const ta = document.createElement("textarea");
        ta.value = orderText;
        ta.style.position = "fixed";
        ta.style.opacity = "0";
        document.body.appendChild(ta);
        ta.focus();
        ta.select();
        document.execCommand("copy");
        document.body.removeChild(ta);
      }
      setCopied(true);
      setTimeout(() => setCopied(false), 2500);
    } catch (err) {
      setCopied(false);
    }
  }

  return (
    <div
      style={{ background: t.bg, color: t.text }}
      className="min-h-screen w-full font-sans transition-colors duration-300"
    >
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Fraunces:opsz,wght@9..144,400;9..144,600;9..144,700&family=Work+Sans:wght@400;500;600&display=swap');
        .ss-serif { font-family: 'Fraunces', Georgia, serif; }
        .ss-sans { font-family: 'Work Sans', system-ui, sans-serif; }
        .ss-badge { font-size: 11px; }
        .ss-cart-badge { font-size: 10px; width: 18px; height: 18px; }

        /* Layout grids defined here with real media queries so behavior is
           guaranteed on every screen size, independent of whichever
           Tailwind utility subset is available in this preview. */
        .rg-hero {
          display: grid;
          grid-template-columns: 1fr;
          gap: 24px;
          align-items: center;
        }
        .rg-trust {
          display: grid;
          grid-template-columns: 1fr;
          gap: 12px;
        }
        .rg-products {
          display: grid;
          grid-template-columns: 1fr;
          gap: 20px;
        }
        @media (min-width: 560px) {
          .rg-trust { grid-template-columns: repeat(2, 1fr); }
        }
        @media (min-width: 640px) {
          .rg-products { grid-template-columns: repeat(2, 1fr); }
        }
        @media (min-width: 900px) {
          .rg-hero { grid-template-columns: 1fr 1fr; gap: 40px; }
        }
        @media (min-width: 960px) {
          .rg-trust { grid-template-columns: repeat(4, 1fr); }
        }
        @media (min-width: 1000px) {
          .rg-products { grid-template-columns: repeat(3, 1fr); }
        }
      `}</style>

      <div className="ss-sans">
        {/* ---------------- HEADER ---------------- */}
        <header
          className="sticky top-0 z-30 backdrop-blur border-b"
          style={{ background: dark ? "rgba(23,19,14,0.85)" : "rgba(251,246,234,0.85)", borderColor: t.border }}
        >
          <div className="max-w-6xl mx-auto flex items-center justify-between px-4 sm:px-5 py-3 sm:py-4 gap-2">
            <div className="flex items-center gap-2 min-w-0">
              <BrandMark className="w-8 h-8 sm:w-9 sm:h-9 shrink-0" />
              <div className="min-w-0">
                <div className="ss-serif text-lg sm:text-xl leading-none truncate" style={{ color: t.text }}>Sathva Siri</div>
                <div className="ss-badge truncate" style={{ color: t.textMuted }}>Purity is our pride</div>
              </div>
            </div>
            <div className="flex items-center gap-2 sm:gap-3 shrink-0">
              <button
                onClick={() => setDark((d) => !d)}
                aria-label="Toggle theme"
                className="w-9 h-9 rounded-full flex items-center justify-center border transition"
                style={{ borderColor: t.border, color: t.gold }}
              >
                {dark ? <Sun size={17} /> : <Moon size={17} />}
              </button>
              <button
                onClick={() => setCartOpen(true)}
                className="relative w-9 h-9 rounded-full flex items-center justify-center border"
                style={{ borderColor: t.border, color: t.text }}
                aria-label="Open cart"
              >
                <ShoppingBag size={17} />
                {cartCount > 0 && (
                  <span
                    className="ss-cart-badge absolute -top-1.5 -right-1.5 rounded-full flex items-center justify-center font-semibold"
                    style={{ background: t.gold, color: dark ? "#17130E" : "#fff" }}
                  >
                    {cartCount}
                  </span>
                )}
              </button>
            </div>
          </div>
        </header>

        {/* ---------------- HERO ---------------- */}
        <section className="rg-hero max-w-6xl mx-auto px-4 sm:px-5 pt-8 sm:pt-14 pb-8 sm:pb-10">
          <div>
            <div className="inline-flex items-center gap-2 text-xs px-3 py-1 rounded-full border mb-4 sm:mb-5" style={{ borderColor: t.border, color: t.green }}>
              <Leaf size={13} /> From the Malenadu hills, Shivamogga
            </div>
            <h1 className="ss-serif text-3xl sm:text-4xl md:text-5xl leading-tight mb-4" style={{ color: t.text }}>
              Farm goods, pressed and harvested the old way.
            </h1>
            <p className="text-sm sm:text-base mb-6 sm:mb-7 max-w-md" style={{ color: t.textMuted }}>
              Chillies, honey, ghee, and ganna-pressed oils from Kalgadde, Theginkoppa —
              no additives, no shortcuts, just what the land gives.
            </p>
            <div className="flex flex-wrap gap-3">
              <a
                href="#shop"
                onClick={(e) => { e.preventDefault(); scrollToSection("shop"); }}
                className="px-5 py-3 rounded-lg text-sm font-medium transition-transform duration-150 hover:-translate-y-0.5 hover:shadow-lg active:translate-y-0 active:shadow-none cursor-pointer"
                style={{ background: t.gold, color: dark ? "#17130E" : "#fff" }}
              >
                Shop the collection
              </a>
              <a
                href="#contact"
                onClick={(e) => { e.preventDefault(); scrollToSection("contact"); }}
                className="px-5 py-3 rounded-lg text-sm font-medium border transition-transform duration-150 hover:-translate-y-0.5 hover:shadow-lg active:translate-y-0 active:shadow-none cursor-pointer"
                style={{ borderColor: t.border, color: t.text }}
              >
                Contact us
              </a>
            </div>
          </div>
          <div
            className="relative rounded-2xl overflow-hidden border"
            style={{ borderColor: t.border, background: t.surfaceAlt }}
          >
            <div
              className="flex transition-transform ease-in-out"
              style={{ transitionDuration: "700ms", transform: `translateX(-${slide * 100}%)` }}
            >
              {HERO_SLIDES.map((s) => (
                <div key={s.key} className="w-full h-full shrink-0" style={{ aspectRatio: "4/3" }}>
                  <img src={PRODUCT_IMAGES[s.key]} alt={s.caption} className="w-full h-full object-cover" />
                </div>
              ))}
            </div>
            <div
              className="absolute bottom-0 left-0 right-0 p-4 sm:p-5"
              style={{ background: "linear-gradient(to top, rgba(0,0,0,0.65), transparent)" }}
            >
              <p className="ss-serif text-base sm:text-lg text-white">{HERO_SLIDES[slide].caption}</p>
            </div>
            <div className="absolute top-3 right-3 flex gap-1.5">
              {HERO_SLIDES.map((s, i) => (
                <span
                  key={s.key}
                  className="rounded-full transition-all"
                  style={{
                    width: i === slide ? 16 : 6,
                    height: 6,
                    background: i === slide ? t.gold : "rgba(255,255,255,0.6)",
                  }}
                />
              ))}
            </div>
          </div>
        </section>

        {/* ---------------- TRUST STRIP ---------------- */}
        <section className="max-w-6xl mx-auto px-4 sm:px-5 pb-4">
          <div className="rg-trust text-sm">
            {["100% pure & natural", "No additives, no preservatives", "Ganna / Bilona hand-methods", "FSSAI registered"].map((x) => (
              <div key={x} className="flex items-center gap-2 px-3 py-3 rounded-lg border" style={{ borderColor: t.border, color: t.textMuted }}>
                <Check size={15} className="shrink-0" style={{ color: t.green }} /> {x}
              </div>
            ))}
          </div>
        </section>

        {/* ---------------- PRODUCTS ---------------- */}
        <section id="shop" className="max-w-6xl mx-auto px-4 sm:px-5 py-10 sm:py-12">
          <div className="flex flex-wrap items-baseline justify-between gap-2 mb-6">
            <h2 className="ss-serif text-xl sm:text-2xl" style={{ color: t.text }}>The Collection</h2>
            <span className="text-xs sm:text-sm" style={{ color: t.textMuted }}>{PRODUCTS.length} products, made in small batches.</span>
          </div>
          <div className="rg-products">
            {PRODUCTS.map((p) => (
              <div key={p.id} className="rounded-2xl border overflow-hidden flex flex-col" style={{ borderColor: t.border, background: t.surface }}>
                <div
                  className="aspect-square overflow-hidden cursor-pointer group relative"
                  onClick={() => setViewProduct(p)}
                >
                  <img
                    src={PRODUCT_IMAGES[p.id]}
                    alt={p.name}
                    className="w-full h-full object-cover object-center transition-transform duration-300 group-hover:scale-105"
                  />
                </div>
                <div className="p-4 sm:p-5 flex flex-col flex-1">
                  <span className="ss-badge uppercase tracking-wide mb-1" style={{ color: t.green }}>{p.tag}</span>
                  <h3 className="ss-serif text-lg mb-0.5" style={{ color: t.text }}>{p.name}</h3>
                  <p className="text-xs mb-2" style={{ color: t.textMuted }}>{p.sub}</p>
                  <p className="text-sm mb-4 flex-1" style={{ color: t.textMuted }}>{p.desc}</p>
                  <div className="flex items-center justify-between mb-4">
                    <span className="ss-serif text-xl" style={{ color: t.text }}>₹{p.price}</span>
                    <span className="text-xs" style={{ color: t.textMuted }}>/ {p.unit}</span>
                  </div>
                  <div className="flex flex-col sm:flex-row gap-2">
                    <button
                      onClick={() => addToCart(p.id)}
                      className="flex-1 px-3 py-2.5 rounded-lg text-sm font-medium border flex items-center justify-center gap-1.5"
                      style={{ borderColor: t.border, color: t.text }}
                    >
                      <Plus size={14} /> Add to cart
                    </button>
                    <button
                      onClick={() => buyNow(p)}
                      className="flex-1 px-3 py-2.5 rounded-lg text-sm font-medium"
                      style={{ background: t.gold, color: dark ? "#17130E" : "#fff" }}
                    >
                      Buy now
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </section>

        {/* ---------------- FOOTER / CONTACT ---------------- */}
        <footer id="contact" className="border-t mt-10" style={{ borderColor: t.border, background: t.surfaceAlt }}>
          <div className="max-w-6xl mx-auto px-5 py-10 grid md:grid-cols-2 gap-6">
            <div>
              <div className="ss-serif text-lg mb-2" style={{ color: t.text }}>Sathva Siri</div>
              <p className="text-sm max-w-sm" style={{ color: t.textMuted }}>
                Pure heritage, pure taste — farm goods from the Malenadu hills, made with tradition and trust.
              </p>
            </div>
            <div className="text-sm space-y-2" style={{ color: t.textMuted }}>
              <div className="flex flex-wrap items-center gap-2">
                <Phone size={14} className="shrink-0" />
                <a href="tel:+918088339295" className="hover:underline" style={{ color: t.textMuted }}>80883 39295</a>
                <span>·</span>
                <a href="tel:+919380712956" className="hover:underline" style={{ color: t.textMuted }}>93807 12956</a>
              </div>
              <div className="flex items-center gap-2">
                <Mail size={14} className="shrink-0" />
                <a href={`mailto:${CONTACT_EMAIL}`} className="hover:underline break-all" style={{ color: t.textMuted }}>{CONTACT_EMAIL}</a>
              </div>
              <div className="flex items-center gap-2">
                <Instagram size={14} className="shrink-0" />
                <a
                  href="https://www.instagram.com/sathva_siri?igsh=d2c5enI5eHRkcXpq"
                  target="_blank"
                  rel="noopener noreferrer"
                  className="hover:underline"
                  style={{ color: t.textMuted }}
                >
                  @sathva_siri
                </a>
              </div>
              <div className="flex items-start gap-2"><MapPin size={14} className="mt-0.5 shrink-0" /> Kalgadde, Theginkoppa (P), Thirthahalli (T), Shivamogga (D), Karnataka – 577414</div>
            </div>
          </div>
          <div className="text-center text-xs pb-6" style={{ color: t.textMuted }}>© {new Date().getFullYear()} Sathva Siri. All rights reserved.</div>
        </footer>
      </div>

      {/* ---------------- CART DRAWER ---------------- */}
      {cartOpen && (
        <div className="fixed inset-0 z-40 flex justify-end">
          <div className="absolute inset-0 bg-black/40" onClick={() => setCartOpen(false)} />
          <div className="relative w-full max-w-sm h-full flex flex-col ss-sans" style={{ background: t.surface, color: t.text }}>
            <div className="flex items-center justify-between px-5 py-4 border-b" style={{ borderColor: t.border }}>
              <h3 className="ss-serif text-lg">Your cart</h3>
              <button onClick={() => setCartOpen(false)} style={{ color: t.textMuted }}><X size={18} /></button>
            </div>
            <div className="flex-1 overflow-y-auto px-5 py-4 space-y-4">
              {cartLines.length === 0 && <p className="text-sm" style={{ color: t.textMuted }}>Your cart is empty.</p>}
              {cartLines.map((l) => (
                <div key={l.id} className="flex gap-3 items-center">
                  <div className="w-14 h-14 rounded-lg overflow-hidden shrink-0 border" style={{ borderColor: t.border }}>
                    <img src={PRODUCT_IMAGES[l.id]} alt={l.name} className="w-full h-full object-cover" />
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-medium truncate">{l.name}</p>
                    <p className="text-xs" style={{ color: t.textMuted }}>₹{l.price} / {l.unit}</p>
                    <div className="flex items-center gap-2 mt-1">
                      <button onClick={() => setQty(l.id, l.qty - 1)} className="w-6 h-6 rounded border flex items-center justify-center" style={{ borderColor: t.border }}><Minus size={12} /></button>
                      <span className="text-sm w-5 text-center">{l.qty}</span>
                      <button onClick={() => setQty(l.id, l.qty + 1)} className="w-6 h-6 rounded border flex items-center justify-center" style={{ borderColor: t.border }}><Plus size={12} /></button>
                      <button onClick={() => removeItem(l.id)} className="ml-2" style={{ color: t.textMuted }}><Trash2 size={14} /></button>
                    </div>
                  </div>
                  <div className="text-sm font-medium">₹{l.qty * l.price}</div>
                </div>
              ))}
            </div>
            {cartLines.length > 0 && (
              <div className="px-5 py-4 border-t" style={{ borderColor: t.border }}>
                <div className="flex justify-between text-sm mb-3">
                  <span style={{ color: t.textMuted }}>Total</span>
                  <span className="ss-serif text-lg">₹{cartTotal}</span>
                </div>
                <button
                  onClick={() => { setCartOpen(false); checkoutCart(); }}
                  className="w-full py-3 rounded-lg text-sm font-medium"
                  style={{ background: t.gold, color: dark ? "#17130E" : "#fff" }}
                >
                  Proceed to buy
                </button>
              </div>
            )}
          </div>
        </div>
      )}

      {/* ---------------- CHECKOUT MODAL ---------------- */}
      {checkoutOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-black/50" onClick={() => setCheckoutOpen(false)} />
          <div className="relative w-full max-w-md rounded-2xl p-6 ss-sans" style={{ background: t.surface, color: t.text }}>
            <button onClick={() => setCheckoutOpen(false)} className="absolute top-4 right-4" style={{ color: t.textMuted }}><X size={18} /></button>

            {!placed ? (
              <>
                <h3 className="ss-serif text-xl mb-1">Complete your order</h3>
                <p className="text-xs mb-4" style={{ color: t.textMuted }}>
                  We'll send your order details to our team and reach out to confirm.
                </p>
                <div className="rounded-lg p-3 mb-4 text-sm space-y-1" style={{ background: t.surfaceAlt }}>
                  {itemsForCheckout.map((l) => (
                    <div key={l.id} className="flex justify-between">
                      <span>{l.name} × {l.qty}</span>
                      <span>₹{l.qty * l.price}</span>
                    </div>
                  ))}
                  <div className="flex justify-between font-medium pt-1 border-t mt-1" style={{ borderColor: t.border }}>
                    <span>Total</span><span>₹{checkoutTotal}</span>
                  </div>
                </div>
                <form onSubmit={submitOrder} className="space-y-3">
                  <input
                    required placeholder="Full name" value={form.name}
                    onChange={(e) => setForm((f) => ({ ...f, name: e.target.value }))}
                    className="w-full px-3 py-2.5 rounded-lg border text-sm bg-transparent"
                    style={{ borderColor: t.border, color: t.text }}
                  />
                  <input
                    type="tel" inputMode="numeric" maxLength={10}
                    required placeholder="Phone number" value={form.phone}
                    onChange={(e) => setForm((f) => ({ ...f, phone: e.target.value.replace(/\D/g, "").slice(0, 10) }))}
                    className="w-full px-3 py-2.5 rounded-lg border text-sm bg-transparent"
                    style={{ borderColor: t.border, color: t.text }}
                  />
                  <input
                    type="email"
                    required placeholder="Email address" value={form.email}
                    onChange={(e) => setForm((f) => ({ ...f, email: e.target.value }))}
                    className="w-full px-3 py-2.5 rounded-lg border text-sm bg-transparent"
                    style={{ borderColor: t.border, color: t.text }}
                  />
                  <textarea
                    required placeholder="Delivery address" value={form.address} rows={3}
                    onChange={(e) => setForm((f) => ({ ...f, address: e.target.value }))}
                    className="w-full px-3 py-2.5 rounded-lg border text-sm bg-transparent resize-none"
                    style={{ borderColor: t.border, color: t.text }}
                  />
                  <button
                    type="submit"
                    disabled={sending}
                    className="w-full py-3 rounded-lg text-sm font-medium disabled:opacity-60"
                    style={{ background: t.gold, color: dark ? "#17130E" : "#fff" }}
                  >
                    {sending ? "Sending..." : "Place order"}
                  </button>
                </form>
              </>
            ) : (
              <div className="text-center py-6">
                <div className="w-12 h-12 rounded-full flex items-center justify-center mx-auto mb-3" style={{ background: t.surfaceAlt, color: t.green }}>
                  <Check size={22} />
                </div>
                <h3 className="ss-serif text-xl mb-1">
                  {sendError ? "Order details ready" : "Request sent!"}
                </h3>
                <p className="text-sm mb-4" style={{ color: t.textMuted }}>
                  {sendError || "Your request has been sent — we'll reach out to you shortly to confirm your order."}
                </p>
                {sendError && (
                  <>
                    <a
                      href={mailtoLink}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="block w-full py-3 rounded-lg text-sm font-medium mb-2"
                      style={{ background: t.gold, color: dark ? "#17130E" : "#fff" }}
                    >
                      Open email app
                    </a>
                    <button
                      onClick={copyOrderDetails}
                      className="w-full py-3 rounded-lg text-sm font-medium border mb-2"
                      style={{ borderColor: t.border, color: t.text }}
                    >
                      {copied ? "Copied! Paste it into an email" : "Copy order details"}
                    </button>
                  </>
                )}
                <button onClick={() => setCheckoutOpen(false)} className="w-full px-5 py-2.5 rounded-lg text-sm border" style={{ borderColor: t.border }}>
                  Close
                </button>
              </div>
            )}
          </div>
        </div>
      )}

      {/* ---------------- IMAGE LIGHTBOX ---------------- */}
      {viewProduct && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-black/70" onClick={() => setViewProduct(null)} />
          <div
            className="relative w-full max-w-lg rounded-2xl overflow-hidden ss-sans"
            style={{ background: t.surface, color: t.text }}
          >
            <button
              onClick={() => setViewProduct(null)}
              className="absolute top-3 right-3 z-10 w-8 h-8 rounded-full flex items-center justify-center"
              style={{ background: "rgba(0,0,0,0.5)", color: "#fff" }}
            >
              <X size={16} />
            </button>
            <img
              src={PRODUCT_IMAGES[viewProduct.id]}
              alt={viewProduct.name}
              className="w-full h-auto object-contain"
              style={{ background: t.surfaceAlt, maxHeight: "70vh" }}
            />
            <div className="p-5">
              <span className="ss-badge uppercase tracking-wide mb-1 block" style={{ color: t.green }}>{viewProduct.tag}</span>
              <h3 className="ss-serif text-xl mb-0.5" style={{ color: t.text }}>{viewProduct.name}</h3>
              <p className="text-xs mb-2" style={{ color: t.textMuted }}>{viewProduct.sub}</p>
              <p className="text-sm mb-4" style={{ color: t.textMuted }}>{viewProduct.desc}</p>
              <div className="flex items-center justify-between mb-4">
                <span className="ss-serif text-xl" style={{ color: t.text }}>₹{viewProduct.price}</span>
                <span className="text-xs" style={{ color: t.textMuted }}>/ {viewProduct.unit}</span>
              </div>
              <div className="flex flex-col sm:flex-row gap-2">
                <button
                  onClick={() => { addToCart(viewProduct.id); setViewProduct(null); }}
                  className="flex-1 px-3 py-2.5 rounded-lg text-sm font-medium border flex items-center justify-center gap-1.5"
                  style={{ borderColor: t.border, color: t.text }}
                >
                  <Plus size={14} /> Add to cart
                </button>
                <button
                  onClick={() => { buyNow(viewProduct); setViewProduct(null); }}
                  className="flex-1 px-3 py-2.5 rounded-lg text-sm font-medium"
                  style={{ background: t.gold, color: dark ? "#17130E" : "#fff" }}
                >
                  Buy now
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
